const locales = ["en", "es", "pt-BR", "it"];

const labels = {
  en: { passage: "Passage", check: "Test the distinction", practice: "Apply the idea", good: "That distinction holds.", again: "Look again at the boundary described above." },
  es: { passage: "Pasaje", check: "Comprueba la distinción", practice: "Aplica la idea", good: "La distinción se sostiene.", again: "Vuelve a mirar el límite descrito arriba." },
  "pt-BR": { passage: "Passagem", check: "Teste a distinção", practice: "Aplique a ideia", good: "A distinção se sustenta.", again: "Observe novamente o limite descrito acima." },
  it: { passage: "Passaggio", check: "Verifica la distinzione", practice: "Applica l'idea", good: "La distinzione regge.", again: "Rileggi il confine descritto sopra." }
};

function buildCopy(locale, raw, mode) {
  const text = labels[locale];
  return {
    eyebrow: `${text.passage} ${raw.n}`,
    navTitle: raw.t,
    title: raw.t,
    lede: raw.l,
    body: raw.b,
    concepts: raw.c,
    variation: mode === "spiritual" ? raw.v : undefined,
    limit: mode === "ai" ? raw.v : undefined,
    quiz: {
      title: text.check,
      prompt: raw.q[0],
      choices: [
        { text: raw.q[1], correct: true, feedback: raw.q[4] || text.good },
        { text: raw.q[2], correct: false, feedback: text.again },
        { text: raw.q[3], correct: false, feedback: text.again }
      ],
      success: raw.q[4] || text.good
    },
    exercise: {
      title: text.practice,
      prompt: raw.e[0],
      options: raw.e.slice(1, 4).map((option) => ({ text: option, insight: raw.e[4] })),
      feedback: raw.e[4],
      completedFeedback: raw.e[4]
    },
    sources: raw.s
  };
}

const spiritualLessons = {
  en: [
    { n:"01", t:"Before the threshold", l:"Living traditions are carried by people and communities, not completed by a website.", b:["This journey teaches public history, language, concepts, difference, and respectful observation. It cannot confer initiation, office, lineage, or spiritual authority.","Some knowledge is public, some requires permission, and some belongs to initiated relationships. Respecting that boundary is part of learning—not a missing feature."], c:["public learning","customary access","community authority"], v:"What is public or restricted can vary by house, nation, context, and the decision of knowledge holders.", q:["Which promise can this site responsibly make?","Advanced public literacy","Online initiation","Personal divination","Learning begins by naming the limit."], e:["A visitor sees a no-photography sign. What should guide the response?","Put the camera away","Ask an authorized host if uncertain","Let the community’s rule outrank personal curiosity","Consent is active, contextual, and revocable."], s:["unesco-ethics","unesco-ifa"] },
    { n:"02", t:"People, places, and the Black Atlantic", l:"Candomblé formed in Brazil through African knowledge, resistance, creativity, and new relationships under violent displacement.", b:["Yoruba/Nagô, Ewe-Fon/Jeje, Central African, and other peoples carried languages, philosophies, arts, political memories, and forms of care. They did not arrive without history.","Brazilian houses developed through changing networks of kinship, city life, emancipation, persecution, survival, and dialogue with Africa. No single arrow tells this story."], c:["diaspora","Brazilian formation","historical agency"], v:"Routes, names, and community memories differ. A map should show networks and evidence, not one pure origin.", q:["Which account is most accurate?","Candomblé is a plural Brazilian formation with several African inheritances.","Every house descends from one identical origin.","African history began with Atlantic enslavement.","Plural histories require plural evidence."], e:["How would you repair a one-origin map?","Add several regions and languages","Mark coercion and historical change","Include Brazilian communities as makers of tradition","A responsible map shows people as historical agents."], s:["iphan-terreiros","pares-formation"] },
    { n:"03", t:"One name, many nations", l:"Candomblé names a family of traditions; its nations and houses are related without being interchangeable.", b:["Ketu/Nagô houses commonly use Yoruba-derived orixá vocabulary. Jeje houses center voduns. Angola/Congo houses use inquice or nkisi vocabularies. These are not decorative labels.","Ifá is a Yoruba divinatory and literary tradition. It intersects with parts of Afro-Brazilian history, but it is not the hidden master code of every Candomblé house or every form of cowrie consultation."], c:["nação","orixá · vodum · inquice","Ifá is distinct"], v:"Titles, languages, divinities, rhythms, and practices vary by nation, region, lineage, and house.", q:["Which statement preserves diversity?","Related traditions can retain different vocabularies and authorities.","All Candomblé houses use the same Ifá system.","Nation means a modern passport state.","Similarity does not erase difference."], e:["A caption calls every divinity an orixá. How can it improve?","Name the specific tradition","Use vodum or inquice when context requires","Add a house-specific note when evidence is limited","Context determines responsible vocabulary."], s:["pares-formation","rabelo-obrigacoes"] },
    { n:"04", t:"A world made through relation", l:"Key concepts become clearer as relationships, not as isolated objects or one-word translations.", b:["Ayé and ọ̀run can orient discussion of embodied and spiritual or ancestral domains. Àṣẹ/axé concerns effective, life-bearing capacity in relationship; orí concerns personhood and destiny; ìwà concerns character.","Calling axé a battery, orí a soul, or ọ̀run heaven may offer a first foothold, but each translation loses important dimensions. The comparison must display its failure."], c:["ayé · ọ̀run","àṣẹ · axé","orí · ìwà"], v:"Yoruba, Brazilian Portuguese, practitioner, and scholarly uses overlap without becoming one fixed dictionary.", q:["What is the safest use of an analogy?","A temporary bridge whose difference is stated","A proof that two concepts are identical","A replacement for the original term","An analogy is useful only with its limit visible."], e:["Build a relation map. Which links belong?","Person and community","Character and consequence","Land, memory, and responsibility","The concepts become intelligible through their relations."], s:["unesco-ifa","oluwona-ori"] },
    { n:"05", t:"The house is a teacher", l:"A terreiro is community, sacred place, lineage, memory, work, and a field of care.", b:["Knowledge develops through presence, service, seniority, obligation, attention, and relationship. Public role descriptions can orient a visitor, but a title is not a badge unlocked by collecting information.","A house teaches through people and time. Digital progress can mark what a learner reviewed; it cannot measure religious seniority or authorize responsibility within a community."], c:["terreiro · ilê axé","religious family","time and obligation"], v:"Roles, titles, spatial arrangements, and visitor expectations vary substantially among nations and houses.", q:["What can course progress represent?","Completion of public learning activities","Religious seniority","Authorization to lead a house","Information is not community-granted responsibility."], e:["For a first public visit, what is respectful?","Ask about expectations in advance","Follow the host’s guidance","Treat permission as specific, not permanent","Respectful presence is attentive rather than extractive."], s:["iphan-casa-branca","rabelo-obrigacoes"] },
    { n:"06", t:"Sacred ecology and material relationship", l:"Leaves, waters, earth, iron, fire, cloth, food, and sound participate in relationships; they are not a collectible correspondence chart.", b:["A material’s significance depends on preparation, place, authority, history, and the relationships through which it is used. An ordinary object and a consecrated relationship are not the same thing.","Public learning can discuss ecology, craft, labor, museum history, and consent. It should not publish plant formulas, preparation sequences, ingredients, or instructions for ritual use."], c:["sacred ecology","material relation","consent"], v:"Plant knowledge, colors, objects, foods, and their uses are especially house- and context-specific.", q:["What belongs in a public plant card?","History, ecology, attribution, and a restriction note","A ritual formula and dosage","A guaranteed spiritual effect","Context can be taught without exposing procedure."], e:["How should a museum object be presented?","With provenance","With community context","With rights and access limits","An object is not self-explaining evidence."], s:["mafro-exhibitions","unesco-ethics"] },
    { n:"07", t:"Òrìṣà constellation I: movement and work", l:"Exu, Ogum, Oxóssi, Ossaim, Obaluaiê/Omolu, and Oxumarê are introduced through public themes and relationships.", b:["Crossroads open into roads; roads enter forests; forests hold leaves and provision; vulnerability calls for care; circulation returns what seemed separate to relationship. No profile stands alone.","Òrìṣà are not personality categories, fantasy characters, or single forces of nature. Public profiles are partial orientations shaped by histories, narratives, environments, and communities."], c:["Exu · Ogum","Oxóssi · Ossaim","Obaluaiê · Oxumarê"], v:"Names, narratives, gendered presentations, relationships, and emphases differ across Yoruba and Brazilian settings and among houses.", q:["Which correction is essential?","Exu is not the Devil.","Each Òrìṣà is a personality type.","One image can be a literal portrait.","Demonizing Exu reproduces a harmful falsehood."], e:["A community problem needs communication, roads, food, and care. What does the constellation teach?","Several relationships may matter","No profile explains everything","Action and consequence remain connected","Interdependence is more accurate than choosing a mascot."], s:["british-museum-osun","museu-afro"] },
    { n:"08", t:"Òrìṣà constellation II: waters and authority", l:"Xangô, Oyá/Iansã, Oxum, Obá, Iemanjá, Nanã, Ewá, Logunedé, and Oxalá reveal overlapping relations.", b:["Rivers, storms, mist, mud, ocean, authority, discernment, fertility, seniority, and creation form a changing basin of relationships. The landscape helps orientation but does not contain a divinity.","Female Òrìṣà cannot be reduced to beauty, jealousy, temper, romance, or motherhood. Public narratives need attribution, variation notes, and attention to the social power they describe."], c:["water and change","authority and care","creation and seniority"], v:"Yoruba river associations and Brazilian oceanic emphases show diaspora transformation; narratives also vary by house.", q:["Which profile method is responsible?","Present themes, sources, variation, and a guardrail.","Choose one stereotype for easy memory.","Treat every narrative as a universal biography.","A profile is an attributed opening, not a total identity."], e:["How can an interpretive image avoid claiming a literal portrait?","Use landscape and relation","Label it contemporary interpretation","Avoid copying restricted garments or objects","Visual beauty must not imply documentary authority."], s:["british-museum-osun","museu-afro"] },
    { n:"09", t:"How Ifá holds knowledge", l:"Ifá joins signs, a vast literary corpus, trained memory, interpretation, and counsel.", b:["UNESCO describes 256 odù organizing a continually developing body of ẹsẹ̀. An odù is not a database key with one fixed answer, and a verse is not a detached data row.","A trained diviner works with performance, context, memory, ethics, and a person’s situation. This site can teach public architecture and literary significance; it will not cast, interpret, or prescribe."], c:["16 principal · 256 total","odù and ẹsẹ̀","trained interpretation"], v:"Corpus versions, recitations, offices, and interpretive practices vary across communities and regions.", q:["What does the 256-cell model show here?","A public structural architecture","A randomized personal oracle","A complete mapping from sign to remedy","Structure is not consultation."], e:["Why can the same invented secular parable speak differently in two cases?","Context changes relevance","Interpretation is not mere lookup","Human judgment connects text and situation","A corpus becomes counsel through accountable interpretation."], s:["unesco-ifa","bascom-ifa"] },
    { n:"10", t:"Reading a public celebration", l:"A public celebration may be witnessed without becoming material to copy, record, or reproduce.", b:["Visitors may encounter ordered praise, music, dance, clothing, hospitality, and embodied religious presence. Observation does not grant permission to film, imitate, or reconstruct what was seen.","A ritual-literacy walkthrough teaches preparation, visitor etiquette, visible roles, and consent from the visitor’s viewpoint. It never places the learner inside restricted action or attempts to induce an altered state."], c:["public celebration","visitor conduct","music as knowledge"], v:"Terms, sequence, photography rules, clothing, and visitor access vary by nation, house, and occasion.", q:["What follows from public visibility?","Permission must still be asked and can be refused.","Everything visible may be copied.","A recording can replace presence.","Visibility is not blanket consent."], e:["At a fictional celebration, which choices show care?","Arrive according to guidance","Ask before recording","Do not imitate what you do not understand","Respect continues after the event."], s:["iphan-bembe","unesco-ethics"] },
    { n:"11", t:"Character, destiny, and responsibility", l:"Personhood sits inside relationships: character matters, destiny does not erase agency, and well-being is not purely individual.", b:["Ìwà-pẹ̀lẹ́ points toward cultivated good or gentle character. Orí can hold dimensions of personhood and destiny without making every event fixed in advance.","Public learning becomes ethical when it addresses reciprocity, repair, environment, religious racism, and the effects of our descriptions on real communities."], c:["ìwà-pẹ̀lẹ́","destiny and agency","reciprocity and repair"], v:"Ethical language and the balance between destiny and agency are interpreted through different texts, teachers, and communities.", q:["Which claim avoids fatalism?","Destiny and agency can remain in tension.","Every action is predetermined.","Character has no social consequence.","Responsibility survives uncertainty."], e:["A harmful description circulates online. What can repair include?","Correct the false claim","Center affected communities","Change the practice that enabled harm","Repair joins speech to consequence."], s:["unesco-ifa","ministry-terreiro-policy"] },
    { n:"12", t:"Comparison, syncretism, and return", l:"Comparison can begin understanding, but it must not turn history into a chart of identities.", b:["Catholic–Òrìṣà associations emerged through coercion, persecution, concealment, devotion, survival, creativity, and continuing negotiation. Communities may embrace, reinterpret, or reject particular associations.","A responsible comparison names a useful bridge, a critical difference, and its historical setting. The journey ends by returning authority to living people and by keeping questions open."], c:["compare without equating","historical syncretism","responsible return"], v:"Syncretic relationships differ by place, period, person, and house; no universal saint-to-Òrìṣà table is responsible.", q:["Which formula is acceptable?","Useful similarity + critical difference + historical context","Òrìṣà equals saint","Shared color proves shared identity","Comparison needs both history and a stopping point."], e:["Audit a comparison card. What must it include?","The original concept first","Where the analogy fails","The history that made the comparison possible","A bridge is ethical only when it does not erase either side."], s:["dantas-nago","capone-africa-brazil"] }
  ],
  es: [
    { n:"01", t:"Antes del umbral", l:"Las tradiciones vivas son sostenidas por personas y comunidades; un sitio web no puede completarlas.", b:["Este recorrido enseña historia pública, lenguaje, conceptos, diferencias y observación respetuosa. No confiere iniciación, cargo, linaje ni autoridad espiritual.","Hay conocimiento público, conocimiento que requiere permiso y conocimiento que pertenece a relaciones iniciáticas. Respetar esa frontera es parte del aprendizaje."], c:["aprendizaje público","acceso consuetudinario","autoridad comunitaria"], v:"Lo público y lo reservado varía según casa, nación, contexto y decisión de quienes custodian el conocimiento.", q:["¿Qué promesa puede hacer el sitio?","Alfabetización pública avanzada","Iniciación en línea","Adivinación personal","Aprender comienza por nombrar el límite."], e:["Una visita ve una señal de no fotografiar. ¿Qué guía la respuesta?","Guardar la cámara","Preguntar a una persona autorizada si hay duda","Anteponer la regla comunitaria a la curiosidad","El consentimiento es activo, contextual y revocable."], s:["unesco-ethics","unesco-ifa"] },
    { n:"02", t:"Personas, lugares y el Atlántico Negro", l:"Candomblé se formó en Brasil mediante saberes africanos, resistencia, creatividad y nuevas relaciones bajo desplazamiento violento.", b:["Pueblos yoruba/nagô, ewe-fon/jeje, centroafricanos y otros llevaron lenguas, filosofías, artes, memorias políticas y formas de cuidado.","Las casas brasileñas surgieron en redes cambiantes de parentesco, ciudad, emancipación, persecución, supervivencia y diálogo con África. Una sola flecha no cuenta esta historia."], c:["diáspora","formación brasileña","agencia histórica"], v:"Rutas, nombres y memorias difieren. Un mapa debe mostrar redes y evidencia, no un origen puro.", q:["¿Qué relato es más preciso?","Una formación brasileña plural con varias herencias africanas.","Todas las casas tienen un origen idéntico.","La historia africana comenzó con la esclavización atlántica.","Las historias plurales necesitan evidencia plural."], e:["¿Cómo reparar un mapa de origen único?","Añadir regiones y lenguas","Marcar coerción y cambio histórico","Mostrar comunidades brasileñas como creadoras","Un mapa responsable muestra agentes históricos."], s:["iphan-terreiros","pares-formation"] },
    { n:"03", t:"Un nombre, muchas naciones", l:"Candomblé nombra una familia de tradiciones; sus naciones y casas se relacionan sin ser intercambiables.", b:["Casas Ketu/Nagô suelen usar vocabulario de orixá; casas Jeje centran voduns; casas Angola/Congo usan inquice o nkisi. No son adornos.","Ifá es una tradición yoruba divinatoria y literaria. Se cruza con historias afrobrasileñas, pero no es el código oculto de toda casa ni de toda consulta con caracoles."], c:["nação","orixá · vodum · inquice","Ifá es distinto"], v:"Títulos, lenguas, divinidades, ritmos y prácticas varían por nación, región, linaje y casa.", q:["¿Qué frase conserva la diversidad?","Tradiciones relacionadas pueden tener vocabularios y autoridades diferentes.","Todas las casas usan el mismo sistema de Ifá.","Nación significa Estado moderno.","La semejanza no borra la diferencia."], e:["Un pie de foto llama orixá a toda divinidad. ¿Cómo mejorar?","Nombrar la tradición concreta","Usar vodum o inquice cuando corresponda","Añadir una nota específica de casa","El contexto determina el vocabulario responsable."], s:["pares-formation","rabelo-obrigacoes"] },
    { n:"04", t:"Un mundo hecho de relaciones", l:"Los conceptos clave se comprenden mejor como relaciones, no como objetos aislados o traducciones de una palabra.", b:["Ayé y ọ̀run orientan ámbitos corporales y espirituales o ancestrales. Àṣẹ/axé trata la capacidad eficaz y vital en relación; orí, persona y destino; ìwà, carácter.","Llamar batería a axé, alma a orí o cielo a ọ̀run da un primer apoyo, pero pierde dimensiones. La comparación debe mostrar su fracaso."], c:["ayé · ọ̀run","àṣẹ · axé","orí · ìwà"], v:"Los usos yoruba, brasileños, practicantes y académicos se superponen sin formar un diccionario fijo.", q:["¿Cómo usar una analogía con cuidado?","Como puente temporal cuya diferencia se declara","Como prueba de identidad","Como sustituto del término original","La analogía sirve con su límite visible."], e:["¿Qué conexiones pertenecen al mapa relacional?","Persona y comunidad","Carácter y consecuencia","Tierra, memoria y responsabilidad","Los conceptos se aclaran mediante relaciones."], s:["unesco-ifa","oluwona-ori"] },
    { n:"05", t:"La casa es maestra", l:"Un terreiro es comunidad, lugar sagrado, linaje, memoria, trabajo y campo de cuidado.", b:["El saber crece con presencia, servicio, antigüedad, obligación, atención y relación. Las funciones públicas orientan, pero un título no es una insignia obtenida acumulando datos.","La casa enseña mediante personas y tiempo. El progreso digital marca actividades revisadas; no mide antigüedad religiosa ni autoriza responsabilidades comunitarias."], c:["terreiro · ilê axé","familia religiosa","tiempo y obligación"], v:"Funciones, títulos, espacios y expectativas de visita varían mucho entre naciones y casas.", q:["¿Qué representa el progreso del curso?","Actividades públicas completadas","Antigüedad religiosa","Autorización para dirigir una casa","La información no es responsabilidad otorgada."], e:["¿Qué es respetuoso en una primera visita pública?","Preguntar expectativas antes","Seguir a quien recibe","Tratar el permiso como específico","La presencia respetuosa no extrae."], s:["iphan-casa-branca","rabelo-obrigacoes"] },
    { n:"06", t:"Ecología sagrada y relación material", l:"Hojas, aguas, tierra, hierro, fuego, tela, comida y sonido participan en relaciones; no forman una tabla coleccionable.", b:["El significado de un material depende de preparación, lugar, autoridad, historia y relaciones. Un objeto ordinario no equivale a una relación consagrada.","El aprendizaje público aborda ecología, oficio, trabajo, historia museística y consentimiento. No publica fórmulas vegetales, secuencias, ingredientes ni instrucciones."], c:["ecología sagrada","relación material","consentimiento"], v:"Plantas, colores, objetos, alimentos y usos son especialmente específicos de casa y contexto.", q:["¿Qué cabe en una ficha vegetal pública?","Historia, ecología, atribución y nota de restricción","Fórmula y dosis ritual","Efecto espiritual garantizado","Se enseña contexto sin exponer procedimiento."], e:["¿Cómo presentar un objeto de museo?","Con procedencia","Con contexto comunitario","Con derechos y límites de acceso","Un objeto no se explica solo."], s:["mafro-exhibitions","unesco-ethics"] },
    { n:"07", t:"Constelación de Òrìṣà I: movimiento y trabajo", l:"Exu, Ogum, Oxóssi, Ossaim, Obaluaiê/Omolu y Oxumarê aparecen mediante temas públicos y relaciones.", b:["Encrucijadas abren caminos; los caminos entran al bosque; el bosque guarda hojas y alimento; la vulnerabilidad llama al cuidado; la circulación devuelve todo a la relación.","Los Òrìṣà no son tipos de personalidad, personajes fantásticos ni simples fuerzas naturales. Cada perfil es una orientación parcial."], c:["Exu · Ogum","Oxóssi · Ossaim","Obaluaiê · Oxumarê"], v:"Nombres, relatos, género, relaciones y énfasis difieren entre ámbitos yoruba y brasileños y entre casas.", q:["¿Qué corrección es esencial?","Exu no es el Diablo.","Cada Òrìṣà es un tipo de personalidad.","Una imagen es un retrato literal.","Demonizar a Exu reproduce una falsedad dañina."], e:["Un problema exige comunicación, caminos, alimento y cuidado. ¿Qué enseña la constelación?","Importan varias relaciones","Ningún perfil lo explica todo","Acción y consecuencia siguen unidas","La interdependencia supera a elegir una mascota."], s:["british-museum-osun","museu-afro"] },
    { n:"08", t:"Constelación de Òrìṣà II: aguas y autoridad", l:"Xangô, Oyá/Iansã, Oxum, Obá, Iemanjá, Nanã, Ewá, Logunedé y Oxalá revelan relaciones superpuestas.", b:["Ríos, tormentas, niebla, barro, océano, autoridad, discernimiento, fertilidad, antigüedad y creación forman una cuenca cambiante. El paisaje orienta; no contiene a una divinidad.","Los Òrìṣà femeninos no se reducen a belleza, celos, ira, romance o maternidad. Los relatos públicos exigen atribución y variación."], c:["agua y cambio","autoridad y cuidado","creación y antigüedad"], v:"Asociaciones fluviales yoruba y énfasis oceánicos brasileños muestran transformación diaspórica; los relatos varían por casa.", q:["¿Qué método de perfil es responsable?","Temas, fuentes, variación y advertencia.","Un estereotipo fácil.","Una biografía universal.","Un perfil abre; no totaliza."], e:["¿Cómo evita una imagen parecer retrato literal?","Usar paisaje y relación","Etiquetarla como interpretación","No copiar prendas u objetos restringidos","La belleza visual no concede autoridad documental."], s:["british-museum-osun","museu-afro"] },
    { n:"09", t:"Cómo Ifá sostiene conocimiento", l:"Ifá une signos, un vasto corpus literario, memoria entrenada, interpretación y consejo.", b:["UNESCO describe 256 odù que organizan un cuerpo de ẹsẹ̀ en desarrollo continuo. Un odù no es una clave con una respuesta fija; un verso no es una fila de datos.","La persona formada trabaja con interpretación, contexto, memoria y ética. El sitio enseña arquitectura pública; no lanza, interpreta ni prescribe."], c:["16 principales · 256 total","odù y ẹsẹ̀","interpretación formada"], v:"Versiones, recitaciones, cargos y prácticas interpretativas varían entre comunidades y regiones.", q:["¿Qué muestra aquí la cuadrícula de 256?","Una arquitectura estructural pública","Un oráculo personal al azar","Un mapa completo de remedios","La estructura no es consulta."], e:["¿Por qué una parábola secular inventada cambia entre dos casos?","El contexto cambia la pertinencia","Interpretar no es buscar una fila","El juicio conecta texto y situación","El consejo requiere interpretación responsable."], s:["unesco-ifa","bascom-ifa"] },
    { n:"10", t:"Leer una celebración pública", l:"Una celebración pública puede observarse sin convertirse en material para copiar, grabar o reproducir.", b:["Puede haber alabanza ordenada, música, danza, ropa, hospitalidad y presencia religiosa encarnada. Observar no autoriza filmar o imitar.","El recorrido enseña preparación, etiqueta, funciones visibles y consentimiento desde la posición visitante. Nunca sitúa al aprendiz dentro de acción restringida."], c:["celebración pública","conducta visitante","música como saber"], v:"Términos, secuencias, fotografía, ropa y acceso varían por nación, casa y ocasión.", q:["¿Qué implica la visibilidad pública?","Aún hay que pedir permiso y puede negarse.","Todo lo visible puede copiarse.","Una grabación sustituye la presencia.","La visibilidad no es consentimiento general."], e:["¿Qué decisiones muestran cuidado?","Llegar según la orientación","Preguntar antes de grabar","No imitar lo que no se entiende","El respeto continúa después del evento."], s:["iphan-bembe","unesco-ethics"] },
    { n:"11", t:"Carácter, destino y responsabilidad", l:"La persona vive dentro de relaciones: el carácter importa, el destino no elimina la agencia y el bienestar no es solo individual.", b:["Ìwà-pẹ̀lẹ́ apunta al carácter bueno o sereno cultivado. Orí puede incluir persona y destino sin volver cada acontecimiento inevitable.","El aprendizaje público se hace ético cuando aborda reciprocidad, reparación, ambiente, racismo religioso y efectos sobre comunidades reales."], c:["ìwà-pẹ̀lẹ́","destino y agencia","reciprocidad y reparación"], v:"El lenguaje ético y la tensión entre destino y agencia cambian según textos, docentes y comunidades.", q:["¿Qué frase evita el fatalismo?","Destino y agencia pueden permanecer en tensión.","Toda acción está predeterminada.","El carácter no tiene efecto social.","La responsabilidad sobrevive a la incertidumbre."], e:["Circula una descripción dañina. ¿Qué repara?","Corregir lo falso","Centrar comunidades afectadas","Cambiar la práctica que causó daño","Reparar une palabra y consecuencia."], s:["unesco-ifa","ministry-terreiro-policy"] },
    { n:"12", t:"Comparación, sincretismo y regreso", l:"Comparar puede iniciar comprensión, pero no convertir la historia en una tabla de identidades.", b:["Las asociaciones católicas–Òrìṣà surgieron entre coerción, persecución, ocultamiento, devoción, supervivencia, creatividad y negociación. Las comunidades pueden aceptarlas, reinterpretarlas o rechazarlas.","Una comparación responsable muestra puente útil, diferencia crítica y situación histórica. El recorrido devuelve la autoridad a personas vivas."], c:["comparar sin equiparar","sincretismo histórico","regreso responsable"], v:"Las relaciones sincréticas cambian por lugar, época, persona y casa; ninguna tabla universal es responsable.", q:["¿Qué fórmula sirve?","Semejanza útil + diferencia crítica + contexto histórico","Òrìṣà equivale a santo","Un color compartido prueba identidad","Comparar necesita historia y un punto final."], e:["¿Qué debe incluir una tarjeta comparativa?","El concepto original primero","Dónde falla la analogía","La historia que hizo posible la comparación","Un puente ético no borra ninguno de los lados."], s:["dantas-nago","capone-africa-brazil"] }
  ],
  "pt-BR": [
    { n:"01", t:"Antes da soleira", l:"Tradições vivas são sustentadas por pessoas e comunidades; um site não pode completá-las.", b:["Esta jornada ensina história pública, linguagem, conceitos, diferenças e observação respeitosa. Não confere iniciação, cargo, linhagem ou autoridade espiritual.","Há conhecimento público, conhecimento que exige permissão e conhecimento que pertence a relações iniciáticas. Respeitar essa fronteira faz parte do aprendizado."], c:["aprendizagem pública","acesso costumeiro","autoridade comunitária"], v:"O que é público ou restrito varia conforme casa, nação, contexto e decisão de quem guarda o conhecimento.", q:["Que promessa o site pode fazer?","Alfabetização pública avançada","Iniciação on-line","Divinação pessoal","Aprender começa por nomear o limite."], e:["Uma visita vê uma placa proibindo fotos. O que deve orientar a resposta?","Guardar a câmera","Perguntar a uma pessoa autorizada se houver dúvida","Priorizar a regra comunitária","Consentimento é ativo, contextual e revogável."], s:["unesco-ethics","unesco-ifa"] },
    { n:"02", t:"Pessoas, lugares e o Atlântico Negro", l:"O Candomblé se formou no Brasil por saberes africanos, resistência, criatividade e novas relações sob deslocamento violento.", b:["Povos iorubá/nagô, ewe-fon/jeje, centro-africanos e outros trouxeram línguas, filosofias, artes, memórias políticas e formas de cuidado.","Casas brasileiras cresceram em redes de parentesco, vida urbana, emancipação, perseguição, sobrevivência e diálogo com a África. Uma só seta não conta essa história."], c:["diáspora","formação brasileira","agência histórica"], v:"Rotas, nomes e memórias diferem. Um mapa deve mostrar redes e evidências, não uma origem pura.", q:["Qual relato é mais preciso?","Uma formação brasileira plural com várias heranças africanas.","Toda casa vem de uma origem idêntica.","A história africana começou na escravização atlântica.","Histórias plurais pedem evidências plurais."], e:["Como reparar um mapa de origem única?","Adicionar regiões e línguas","Marcar coerção e mudança histórica","Mostrar comunidades brasileiras como criadoras","Um mapa responsável mostra agentes históricos."], s:["iphan-terreiros","pares-formation"] },
    { n:"03", t:"Um nome, muitas nações", l:"Candomblé nomeia uma família de tradições; suas nações e casas se relacionam sem serem intercambiáveis.", b:["Casas Ketu/Nagô costumam usar vocabulário de orixá; casas Jeje centram voduns; casas Angola/Congo usam inquice ou nkisi. Não são enfeites.","Ifá é uma tradição iorubá divinatória e literária. Cruza histórias afro-brasileiras, mas não é o código oculto de toda casa nem de todo jogo de búzios."], c:["nação","orixá · vodum · inquice","Ifá é distinto"], v:"Títulos, línguas, divindades, ritmos e práticas variam por nação, região, linhagem e casa.", q:["Que frase preserva a diversidade?","Tradições relacionadas podem ter vocabulários e autoridades diferentes.","Todas as casas usam o mesmo Ifá.","Nação significa Estado moderno.","Semelhança não apaga diferença."], e:["Uma legenda chama toda divindade de orixá. Como melhorar?","Nomear a tradição específica","Usar vodum ou inquice quando adequado","Adicionar nota específica da casa","O contexto define o vocabulário responsável."], s:["pares-formation","rabelo-obrigacoes"] },
    { n:"04", t:"Um mundo feito de relações", l:"Conceitos centrais ficam mais claros como relações, não objetos isolados ou traduções de uma palavra.", b:["Ayé e ọ̀run orientam domínios corporais e espirituais ou ancestrais. Àṣẹ/axé trata da capacidade eficaz e vital em relação; orí, pessoa e destino; ìwà, caráter.","Chamar axé de bateria, orí de alma ou ọ̀run de céu oferece apoio inicial, mas perde dimensões. A comparação deve mostrar onde falha."], c:["ayé · ọ̀run","àṣẹ · axé","orí · ìwà"], v:"Usos iorubás, brasileiros, de praticantes e acadêmicos se sobrepõem sem formar um dicionário fixo.", q:["Como usar uma analogia com cuidado?","Como ponte temporária cuja diferença é declarada","Como prova de identidade","Como substituta do termo original","A analogia só ajuda com seu limite visível."], e:["Que conexões cabem no mapa relacional?","Pessoa e comunidade","Caráter e consequência","Terra, memória e responsabilidade","Os conceitos ganham sentido pelas relações."], s:["unesco-ifa","oluwona-ori"] },
    { n:"05", t:"A casa é professora", l:"Um terreiro é comunidade, lugar sagrado, linhagem, memória, trabalho e campo de cuidado.", b:["O saber cresce com presença, serviço, senioridade, obrigação, atenção e relação. Papéis públicos orientam, mas um título não é medalha obtida acumulando informação.","A casa ensina por pessoas e tempo. O progresso digital marca atividades; não mede senioridade religiosa nem autoriza responsabilidades comunitárias."], c:["terreiro · ilê axé","família religiosa","tempo e obrigação"], v:"Papéis, títulos, espaços e expectativas de visita variam muito entre nações e casas.", q:["O que o progresso do curso representa?","Atividades públicas concluídas","Senioridade religiosa","Autorização para dirigir uma casa","Informação não é responsabilidade concedida."], e:["O que é respeitoso numa primeira visita pública?","Perguntar expectativas antes","Seguir quem recebe","Tratar permissão como específica","Presença respeitosa não é extrativa."], s:["iphan-casa-branca","rabelo-obrigacoes"] },
    { n:"06", t:"Ecologia sagrada e relação material", l:"Folhas, águas, terra, ferro, fogo, tecido, comida e som participam de relações; não formam tabela colecionável.", b:["O significado de um material depende de preparo, lugar, autoridade, história e relações. Objeto comum não equivale a relação consagrada.","Aprendizagem pública aborda ecologia, ofício, trabalho, história de museu e consentimento. Não publica fórmulas de folhas, sequências, ingredientes ou instruções."], c:["ecologia sagrada","relação material","consentimento"], v:"Plantas, cores, objetos, alimentos e usos são especialmente específicos de casa e contexto.", q:["O que cabe num cartão público de planta?","História, ecologia, atribuição e nota de restrição","Fórmula e dose ritual","Efeito espiritual garantido","É possível ensinar contexto sem expor procedimento."], e:["Como apresentar um objeto de museu?","Com proveniência","Com contexto comunitário","Com direitos e limites de acesso","Um objeto não se explica sozinho."], s:["mafro-exhibitions","unesco-ethics"] },
    { n:"07", t:"Constelação de Òrìṣà I: movimento e trabalho", l:"Exu, Ogum, Oxóssi, Ossaim, Obaluaiê/Omolu e Oxumarê aparecem por temas públicos e relações.", b:["Encruzilhadas abrem estradas; estradas entram na mata; a mata guarda folhas e alimento; vulnerabilidade chama cuidado; circulação devolve tudo à relação.","Òrìṣà não são tipos de personalidade, personagens de fantasia ou simples forças naturais. Cada perfil é orientação parcial."], c:["Exu · Ogum","Oxóssi · Ossaim","Obaluaiê · Oxumarê"], v:"Nomes, narrativas, gênero, relações e ênfases diferem entre contextos iorubás, brasileiros e casas.", q:["Que correção é essencial?","Exu não é o Diabo.","Cada Òrìṣà é um tipo de personalidade.","Uma imagem é retrato literal.","Demonizar Exu reproduz uma falsidade nociva."], e:["Um problema exige comunicação, estrada, alimento e cuidado. O que a constelação ensina?","Várias relações importam","Nenhum perfil explica tudo","Ação e consequência continuam ligadas","Interdependência é melhor que escolher um mascote."], s:["british-museum-osun","museu-afro"] },
    { n:"08", t:"Constelação de Òrìṣà II: águas e autoridade", l:"Xangô, Oyá/Iansã, Oxum, Obá, Iemanjá, Nanã, Ewá, Logunedé e Oxalá revelam relações sobrepostas.", b:["Rios, tempestades, névoa, lama, oceano, autoridade, discernimento, fertilidade, senioridade e criação formam uma bacia mutável. A paisagem orienta; não contém a divindade.","Òrìṣà femininos não se reduzem a beleza, ciúme, raiva, romance ou maternidade. Narrativas públicas exigem atribuição e variação."], c:["água e mudança","autoridade e cuidado","criação e senioridade"], v:"Associações fluviais iorubás e ênfases oceânicas brasileiras mostram transformação diaspórica; narrativas variam por casa.", q:["Que método de perfil é responsável?","Temas, fontes, variação e alerta.","Um estereótipo fácil.","Uma biografia universal.","Um perfil abre; não totaliza."], e:["Como uma imagem evita parecer retrato literal?","Usar paisagem e relação","Rotulá-la como interpretação","Não copiar roupas ou objetos restritos","Beleza visual não dá autoridade documental."], s:["british-museum-osun","museu-afro"] },
    { n:"09", t:"Como Ifá sustenta conhecimento", l:"Ifá reúne sinais, vasto corpus literário, memória treinada, interpretação e conselho.", b:["A UNESCO descreve 256 odù organizando um corpo de ẹsẹ̀ em desenvolvimento. Odù não é chave com resposta fixa; verso não é linha de banco de dados.","A pessoa formada trabalha com performance, contexto, memória e ética. O site ensina arquitetura pública; não lança, interpreta ou prescreve."], c:["16 principais · 256 total","odù e ẹsẹ̀","interpretação treinada"], v:"Versões, recitações, cargos e práticas interpretativas variam entre comunidades e regiões.", q:["O que a grade de 256 mostra aqui?","Uma arquitetura estrutural pública","Um oráculo pessoal aleatório","Um mapa completo de remédios","Estrutura não é consulta."], e:["Por que uma parábola secular inventada muda entre dois casos?","O contexto muda a relevância","Interpretar não é buscar uma linha","Julgamento liga texto e situação","Conselho exige interpretação responsável."], s:["unesco-ifa","bascom-ifa"] },
    { n:"10", t:"Ler uma celebração pública", l:"Uma celebração pública pode ser testemunhada sem virar material para copiar, gravar ou reproduzir.", b:["Pode haver louvação ordenada, música, dança, roupa, hospitalidade e presença religiosa incorporada. Observar não autoriza filmar ou imitar.","A caminhada ensina preparo, etiqueta, papéis visíveis e consentimento do ponto de vista visitante. Nunca coloca a pessoa dentro de ação restrita."], c:["celebração pública","conduta visitante","música como saber"], v:"Termos, sequência, fotografia, roupas e acesso variam por nação, casa e ocasião.", q:["O que decorre da visibilidade pública?","Permissão ainda deve ser pedida e pode ser negada.","Tudo o que aparece pode ser copiado.","Gravação substitui presença.","Visibilidade não é consentimento geral."], e:["Que decisões mostram cuidado?","Chegar conforme orientação","Perguntar antes de gravar","Não imitar o que não entende","O respeito continua depois do evento."], s:["iphan-bembe","unesco-ethics"] },
    { n:"11", t:"Caráter, destino e responsabilidade", l:"A pessoa existe em relações: caráter importa, destino não elimina agência e bem-estar não é apenas individual.", b:["Ìwà-pẹ̀lẹ́ aponta ao caráter bom ou gentil cultivado. Orí pode reunir pessoa e destino sem tornar cada acontecimento inevitável.","Aprendizagem pública se torna ética ao tratar de reciprocidade, reparação, ambiente, racismo religioso e efeitos sobre comunidades reais."], c:["ìwà-pẹ̀lẹ́","destino e agência","reciprocidade e reparação"], v:"Linguagem ética e tensão entre destino e agência mudam conforme textos, docentes e comunidades.", q:["Que frase evita fatalismo?","Destino e agência podem permanecer em tensão.","Toda ação é predeterminada.","Caráter não tem efeito social.","Responsabilidade sobrevive à incerteza."], e:["Circula uma descrição nociva. O que pode reparar?","Corrigir a falsidade","Centrar comunidades afetadas","Mudar a prática que causou dano","Reparar liga palavra e consequência."], s:["unesco-ifa","ministry-terreiro-policy"] },
    { n:"12", t:"Comparação, sincretismo e retorno", l:"Comparar pode iniciar compreensão, mas não transformar história numa tabela de identidades.", b:["Associações católicas–Òrìṣà surgiram entre coerção, perseguição, ocultamento, devoção, sobrevivência, criatividade e negociação. Comunidades podem acolher, reinterpretar ou rejeitar.","Comparação responsável mostra ponte útil, diferença crítica e situação histórica. A jornada devolve autoridade a pessoas vivas."], c:["comparar sem igualar","sincretismo histórico","retorno responsável"], v:"Relações sincréticas mudam por lugar, época, pessoa e casa; nenhuma tabela universal é responsável.", q:["Que fórmula funciona?","Semelhança útil + diferença crítica + contexto histórico","Òrìṣà é igual a santo","Uma cor compartilhada prova identidade","Comparar precisa de história e ponto de parada."], e:["O que um cartão comparativo deve incluir?","O conceito original primeiro","Onde a analogia falha","A história que possibilitou a comparação","Uma ponte ética não apaga nenhum lado."], s:["dantas-nago","capone-africa-brazil"] }
  ],
  it: [
    { n:"01", t:"Prima della soglia", l:"Le tradizioni vive sono sostenute da persone e comunità; un sito non può completarle.", b:["Il percorso insegna storia pubblica, linguaggio, concetti, differenze e osservazione rispettosa. Non conferisce iniziazione, ruolo, lignaggio o autorità spirituale.","Alcuni saperi sono pubblici, altri richiedono permesso, altri appartengono a relazioni iniziatiche. Rispettare questo confine è parte dell'apprendimento."], c:["apprendimento pubblico","accesso consuetudinario","autorità comunitaria"], v:"Ciò che è pubblico o riservato varia per casa, nazione, contesto e decisione dei detentori del sapere.", q:["Quale promessa può fare il sito?","Alfabetizzazione pubblica avanzata","Iniziazione online","Divinazione personale","Imparare comincia dal limite."], e:["Una visita vede il divieto di fotografare. Che cosa guida la risposta?","Riporre la fotocamera","Chiedere a una persona autorizzata","Anteporre la regola comunitaria alla curiosità","Il consenso è attivo, contestuale e revocabile."], s:["unesco-ethics","unesco-ifa"] },
    { n:"02", t:"Persone, luoghi e Atlantico Nero", l:"Il Candomblé si è formato in Brasile attraverso saperi africani, resistenza, creatività e nuove relazioni sotto spostamento violento.", b:["Popoli yoruba/nagô, ewe-fon/jeje, centroafricani e altri portarono lingue, filosofie, arti, memorie politiche e forme di cura.","Le case brasiliane crebbero in reti di parentela, città, emancipazione, persecuzione, sopravvivenza e dialogo con l'Africa. Una freccia sola non racconta la storia."], c:["diaspora","formazione brasiliana","azione storica"], v:"Rotte, nomi e memorie differiscono. Una mappa deve mostrare reti e prove, non un'origine pura.", q:["Quale racconto è più accurato?","Una formazione brasiliana plurale con diverse eredità africane.","Ogni casa ha un'origine identica.","La storia africana iniziò con la schiavitù atlantica.","Storie plurali richiedono prove plurali."], e:["Come correggere una mappa a origine unica?","Aggiungere regioni e lingue","Segnare coercizione e cambiamento","Mostrare le comunità brasiliane come creatrici","Una mappa responsabile mostra soggetti storici."], s:["iphan-terreiros","pares-formation"] },
    { n:"03", t:"Un nome, molte nazioni", l:"Candomblé indica una famiglia di tradizioni; nazioni e case sono collegate senza essere intercambiabili.", b:["Le case Ketu/Nagô usano spesso il vocabolario orixá; le Jeje centrano i vodun; le Angola/Congo usano inquice o nkisi. Non sono etichette decorative.","Ifá è una tradizione yoruba divinatoria e letteraria. Interseca storie afro-brasiliane, ma non è il codice nascosto di ogni casa o consultazione con conchiglie."], c:["nação","orixá · vodum · inquice","Ifá è distinto"], v:"Titoli, lingue, divinità, ritmi e pratiche variano per nazione, regione, lignaggio e casa.", q:["Quale frase conserva la diversità?","Tradizioni collegate possono mantenere lessici e autorità differenti.","Tutte le case usano lo stesso Ifá.","Nazione significa Stato moderno.","La somiglianza non cancella la differenza."], e:["Una didascalia chiama ogni divinità orixá. Come migliorarla?","Nominare la tradizione","Usare vodum o inquice quando serve","Aggiungere una nota specifica della casa","Il contesto determina il lessico responsabile."], s:["pares-formation","rabelo-obrigacoes"] },
    { n:"04", t:"Un mondo fatto di relazioni", l:"I concetti chiave si comprendono meglio come relazioni, non come oggetti isolati o traduzioni di una parola.", b:["Ayé e ọ̀run orientano ambiti corporei e spirituali o ancestrali. Àṣẹ/axé riguarda capacità efficace e vitale in relazione; orí, persona e destino; ìwà, carattere.","Chiamare axé batteria, orí anima o ọ̀run paradiso offre un primo appiglio ma perde dimensioni. Il confronto deve mostrare il proprio fallimento."], c:["ayé · ọ̀run","àṣẹ · axé","orí · ìwà"], v:"Usi yoruba, brasiliani, praticanti e accademici si sovrappongono senza formare un dizionario fisso.", q:["Come usare un'analogia con cura?","Come ponte temporaneo con differenza dichiarata","Come prova d'identità","Come sostituto del termine","L'analogia serve con il limite visibile."], e:["Quali legami appartengono alla mappa?","Persona e comunità","Carattere e conseguenza","Terra, memoria e responsabilità","I concetti diventano chiari nelle relazioni."], s:["unesco-ifa","oluwona-ori"] },
    { n:"05", t:"La casa insegna", l:"Un terreiro è comunità, luogo sacro, lignaggio, memoria, lavoro e campo di cura.", b:["Il sapere cresce con presenza, servizio, anzianità, obbligo, attenzione e relazione. I ruoli pubblici orientano, ma un titolo non è un distintivo ottenuto accumulando dati.","La casa insegna attraverso persone e tempo. Il progresso digitale segna attività svolte; non misura anzianità religiosa né autorizza responsabilità comunitarie."], c:["terreiro · ilê axé","famiglia religiosa","tempo e obbligo"], v:"Ruoli, titoli, spazi e aspettative dei visitatori variano molto tra nazioni e case.", q:["Che cosa rappresenta il progresso del corso?","Attività pubbliche completate","Anzianità religiosa","Autorizzazione a guidare una casa","L'informazione non è responsabilità concessa."], e:["Che cosa è rispettoso alla prima visita?","Chiedere prima le aspettative","Seguire chi accoglie","Trattare il permesso come specifico","La presenza rispettosa non estrae."], s:["iphan-casa-branca","rabelo-obrigacoes"] },
    { n:"06", t:"Ecologia sacra e relazione materiale", l:"Foglie, acque, terra, ferro, fuoco, stoffa, cibo e suono partecipano a relazioni; non formano una tabella da collezione.", b:["Il significato di un materiale dipende da preparazione, luogo, autorità, storia e relazioni. Un oggetto comune non equivale a una relazione consacrata.","L'apprendimento pubblico tratta ecologia, artigianato, lavoro, museo e consenso. Non pubblica formule vegetali, sequenze, ingredienti o istruzioni."], c:["ecologia sacra","relazione materiale","consenso"], v:"Piante, colori, oggetti, cibi e usi sono particolarmente specifici della casa e del contesto.", q:["Che cosa entra in una scheda pubblica di una pianta?","Storia, ecologia, attribuzione e nota di restrizione","Formula e dose rituale","Effetto spirituale garantito","Il contesto si insegna senza esporre procedure."], e:["Come presentare un oggetto museale?","Con provenienza","Con contesto comunitario","Con diritti e limiti d'accesso","Un oggetto non si spiega da solo."], s:["mafro-exhibitions","unesco-ethics"] },
    { n:"07", t:"Costellazione Òrìṣà I: movimento e lavoro", l:"Exu, Ogum, Oxóssi, Ossaim, Obaluaiê/Omolu e Oxumarê sono introdotti attraverso temi pubblici e relazioni.", b:["Gli incroci aprono strade; le strade entrano nella foresta; la foresta custodisce foglie e nutrimento; la vulnerabilità chiama cura; la circolazione riporta tutto alla relazione.","Gli Òrìṣà non sono tipi di personalità, personaggi fantastici o semplici forze naturali. Ogni profilo è un orientamento parziale."], c:["Exu · Ogum","Oxóssi · Ossaim","Obaluaiê · Oxumarê"], v:"Nomi, racconti, genere, relazioni ed enfasi differiscono tra contesti yoruba, brasiliani e case.", q:["Quale correzione è essenziale?","Exu non è il Diavolo.","Ogni Òrìṣà è un tipo psicologico.","Un'immagine è un ritratto letterale.","Demonizzare Exu riproduce una falsità dannosa."], e:["Un problema richiede comunicazione, strada, cibo e cura. Che cosa insegna la costellazione?","Contano più relazioni","Nessun profilo spiega tutto","Azione e conseguenza restano unite","L'interdipendenza supera la mascotte."], s:["british-museum-osun","museu-afro"] },
    { n:"08", t:"Costellazione Òrìṣà II: acque e autorità", l:"Xangô, Oyá/Iansã, Oxum, Obá, Iemanjá, Nanã, Ewá, Logunedé e Oxalá mostrano relazioni sovrapposte.", b:["Fiumi, tempeste, nebbia, fango, oceano, autorità, discernimento, fertilità, anzianità e creazione formano un bacino mutevole. Il paesaggio orienta; non contiene la divinità.","Gli Òrìṣà femminili non si riducono a bellezza, gelosia, collera, amore o maternità. I racconti pubblici richiedono attribuzione e variazione."], c:["acqua e cambiamento","autorità e cura","creazione e anzianità"], v:"Associazioni fluviali yoruba ed enfasi oceaniche brasiliane mostrano trasformazione diasporica; i racconti variano per casa.", q:["Quale metodo è responsabile?","Temi, fonti, variazione e avvertenza.","Uno stereotipo facile.","Una biografia universale.","Un profilo apre; non esaurisce."], e:["Come evitare che un'immagine sembri ritratto letterale?","Usare paesaggio e relazione","Etichettarla come interpretazione","Non copiare abiti o oggetti riservati","La bellezza non dà autorità documentaria."], s:["british-museum-osun","museu-afro"] },
    { n:"09", t:"Come Ifá custodisce conoscenza", l:"Ifá unisce segni, vasto corpus letterario, memoria addestrata, interpretazione e consiglio.", b:["UNESCO descrive 256 odù che organizzano un corpo di ẹsẹ̀ in sviluppo. Un odù non è una chiave con risposta fissa; un verso non è una riga di dati.","La persona formata lavora con esecuzione, contesto, memoria ed etica. Il sito insegna l'architettura pubblica; non lancia, interpreta o prescrive."], c:["16 principali · 256 totali","odù ed ẹsẹ̀","interpretazione formata"], v:"Versioni, recitazioni, ruoli e pratiche interpretative variano tra comunità e regioni.", q:["Che cosa mostra la griglia di 256?","Un'architettura strutturale pubblica","Un oracolo personale casuale","Una mappa completa di rimedi","La struttura non è consultazione."], e:["Perché una parabola secolare inventata cambia in due casi?","Il contesto cambia la rilevanza","Interpretare non è cercare una riga","Il giudizio collega testo e situazione","Il consiglio richiede interpretazione responsabile."], s:["unesco-ifa","bascom-ifa"] },
    { n:"10", t:"Leggere una celebrazione pubblica", l:"Una celebrazione pubblica può essere osservata senza diventare materiale da copiare, registrare o riprodurre.", b:["Si possono incontrare lode ordinata, musica, danza, abiti, ospitalità e presenza religiosa incarnata. Osservare non autorizza a filmare o imitare.","Il percorso insegna preparazione, comportamento, ruoli visibili e consenso dal punto di vista del visitatore. Non pone mai l'allievo dentro azioni riservate."], c:["celebrazione pubblica","condotta del visitatore","musica come sapere"], v:"Termini, sequenze, fotografie, abiti e accesso variano per nazione, casa e occasione.", q:["Che cosa segue dalla visibilità pubblica?","Il permesso va ancora chiesto e può essere negato.","Tutto ciò che si vede si può copiare.","La registrazione sostituisce la presenza.","Visibilità non significa consenso generale."], e:["Quali scelte mostrano cura?","Arrivare secondo le indicazioni","Chiedere prima di registrare","Non imitare ciò che non si comprende","Il rispetto continua dopo l'evento."], s:["iphan-bembe","unesco-ethics"] },
    { n:"11", t:"Carattere, destino e responsabilità", l:"La persona vive nelle relazioni: il carattere conta, il destino non elimina l'azione e il benessere non è solo individuale.", b:["Ìwà-pẹ̀lẹ́ indica il carattere buono o mite coltivato. Orí può includere persona e destino senza rendere inevitabile ogni evento.","L'apprendimento pubblico diventa etico quando affronta reciprocità, riparazione, ambiente, razzismo religioso ed effetti sulle comunità reali."], c:["ìwà-pẹ̀lẹ́","destino e azione","reciprocità e riparazione"], v:"Il linguaggio etico e la tensione tra destino e azione cambiano secondo testi, insegnanti e comunità.", q:["Quale frase evita il fatalismo?","Destino e azione possono restare in tensione.","Ogni azione è predeterminata.","Il carattere non ha effetti sociali.","La responsabilità sopravvive all'incertezza."], e:["Circola una descrizione dannosa. Che cosa ripara?","Correggere il falso","Centrare le comunità colpite","Cambiare la pratica che ha causato danno","Riparare collega parola e conseguenza."], s:["unesco-ifa","ministry-terreiro-policy"] },
    { n:"12", t:"Confronto, sincretismo e ritorno", l:"Il confronto può iniziare la comprensione, ma non trasformare la storia in una tabella di identità.", b:["Le associazioni cattoliche–Òrìṣà nacquero tra coercizione, persecuzione, occultamento, devozione, sopravvivenza, creatività e negoziazione. Le comunità possono accoglierle, reinterpretarle o rifiutarle.","Un confronto responsabile mostra ponte utile, differenza critica e situazione storica. Il percorso restituisce autorità alle persone vive."], c:["confrontare senza equiparare","sincretismo storico","ritorno responsabile"], v:"Le relazioni sincretiche cambiano per luogo, epoca, persona e casa; nessuna tabella universale è responsabile.", q:["Quale formula funziona?","Somiglianza utile + differenza critica + contesto storico","Òrìṣà uguale santo","Un colore condiviso prova identità","Confrontare richiede storia e un punto di arresto."], e:["Che cosa deve includere una scheda comparativa?","Il concetto originale prima","Dove fallisce l'analogia","La storia che rese possibile il confronto","Un ponte etico non cancella nessun lato."], s:["dantas-nago","capone-africa-brazil"] }
  ]
};

const aiLessons = {
  en: [
    { n:"01", t:"Define the system boundary", l:"A useful technical model begins by stating what is inside scope, what remains outside, and who owns the decision.", b:["This path examines observable inputs, transformations, outputs, constraints, and review points. It does not treat fluent output as proof of complete understanding.","A boundary is part of the specification. It prevents a limited tool from silently becoming the authority for a larger human problem."], c:["scope","observable behavior","decision ownership"], v:"A computational model cannot supply lived experience, consent, independent moral standing, or accountable judgment.", q:["What belongs in a responsible specification?","Authorized task and explicit exclusions","A claim of unlimited competence","An invisible decision owner","Scope makes evaluation possible."], e:["Audit a feature request. What should be named?","Affected people","Permitted inputs and outputs","A human owner and appeal path","A system is safer when authority is explicit."], s:[] },
    { n:"02", t:"Trace data provenance", l:"Data arrives through histories of collection, selection, labeling, omission, and power.", b:["A dataset is not a neutral mirror. Its coverage depends on who was measured, which categories were used, what was discarded, and which conditions changed.","Provenance records sources, transformations, rights, time, and known gaps. Without it, model performance can look precise while its foundation stays unreadable."], c:["dataset provenance","selection bias","coverage"], v:"A dataset cannot supply the experiences it excluded or repair harms merely by increasing its row count.", q:["Which practice improves provenance?","Record collection context and known gaps","Erase source history after training","Assume scale removes bias","Traceability supports responsible interpretation."], e:["A dataset performs poorly for one group. What should be inspected?","Coverage","Labels and collection conditions","Who defined success","Failure often begins before training."], s:[] },
    { n:"03", t:"Keep taxonomies versioned", l:"Categories are engineered decisions, not natural facts discovered once and forever.", b:["Labels, classes, and ontologies compress messy situations into usable distinctions. Changing a label definition changes the system even if the code remains the same.","Versioned taxonomies record definitions, owners, evidence, and migration rules. They prevent several incompatible meanings from hiding behind one name."], c:["taxonomy","versioning","semantic drift"], v:"A category system cannot supply a final, context-free classification of people or changing situations.", q:["Why version a taxonomy?","Definitions and consequences change over time.","Names always keep one meaning.","Models infer the intended definition automatically.","Versioning makes meaning inspectable."], e:["Two teams use the same label differently. What helps?","Write each definition","Name its decision owner","Map differences instead of forcing sameness","Shared words do not guarantee shared semantics."], s:[] },
    { n:"04", t:"Represent relation in vector space", l:"Embeddings place items in a learned geometry where distance reflects statistical patterns in training data.", b:["A vector does not store a complete essence. It is a context-dependent representation optimized for tasks and shaped by the corpus, objective, and architecture.","Similarity can support retrieval and clustering, yet close vectors do not prove identical cause, value, or meaning. The metric answers only the question it was built to measure."], c:["embeddings","distance metric","representation"], v:"A vector cannot supply full context, intrinsic meaning, causal knowledge, or a person’s lived point of view.", q:["What does embedding proximity establish?","A learned statistical relationship under a chosen metric","Complete identity","Moral equivalence","Geometric similarity is task-bound evidence."], e:["A search result is close in vector space. What still needs review?","Source context","Task relevance","Potential bias in the metric","Distance is evidence, not a verdict."], s:[] },
    { n:"05", t:"Memory lives in several layers", l:"System memory may mean trained parameters, a finite context window, external retrieval, or stored application state.", b:["These layers behave differently. A prompt changes current activations during ordinary inference; it does not normally rewrite trained weights.","Durable organizational memory also includes documentation, people, procedures, exceptions, and responsibility. A model snapshot captures only a fraction of that system."], c:["parameters","context window","retrieval"], v:"Stored state cannot supply organizational trust, tacit practice, responsibility, or a reliable account of why every decision was made.", q:["What does an ordinary prompt change?","Current activations and output probabilities","All trained weights","The historical training corpus","Inference uses weights; it does not usually retrain them."], e:["A guide needs current policy. Which design is strongest?","Retrieve a versioned source","Show the source date","Keep a human owner for exceptions","Fresh context needs traceable retrieval."], s:[] },
    { n:"06", t:"Infrastructure is part of the model", l:"Compute, chips, energy, networks, cooling, interfaces, and labor shape what a system can do.", b:["Software behavior is bounded by physical resources and operational choices. Latency, capacity, maintenance, and environmental cost are architectural facts, not background details.","A clean interface can hide annotators, operators, moderators, support teams, and affected communities. A complete system map makes these dependencies visible."], c:["compute","material cost","human operations"], v:"An abstract architecture cannot supply energy, maintenance, labor rights, environmental repair, or real-world care.", q:["What belongs in a system diagram?","Compute, people, energy, and failure handling","Only the model box","Only successful outputs","Infrastructure makes capability possible."], e:["A feature looks instant. What should an audit ask?","Where computation happens","Who maintains the service","What costs and failures are externalized","The interface is the surface, not the whole system."], s:[] },
    { n:"07", t:"Capabilities emerge in combination", l:"Large systems can display abilities that were not separately programmed as rules.", b:["Scale, data, optimization, prompting, tools, and evaluation interact. Some capability changes are gradual but become visible only after a threshold or a new test.","Unexpected behavior is not evidence of mystery or unlimited agency. It is a reason for stronger measurement, controlled experiments, and conservative deployment."], c:["emergent behavior","scale","evaluation"], v:"Unexpected capability cannot supply self-knowledge, purpose, moral agency, or authorization to act in the world.", q:["What should follow an unexpected capability?","Targeted evaluation and new safeguards","A claim of unlimited intelligence","Immediate unsupervised deployment","Surprise increases the need for evidence."], e:["A model passes a new test. What should be checked?","Test leakage","Robustness across conditions","Real-world impact and review","One benchmark is not a complete capability map."], s:[] },
    { n:"08", t:"Coordinate many interacting parts", l:"Distributed systems depend on messages, state, timing, authority, and recovery when components disagree.", b:["A system can be locally correct and globally unsafe. Coordination failures appear through stale state, missing messages, duplicated actions, and unclear ownership.","Protocols make order explicit: who may act, which state is current, how conflict resolves, and how a failed step can be reversed."], c:["distributed state","protocol","recovery"], v:"A protocol cannot supply trust, shared purpose, consent, or judgment about every exceptional case.", q:["What improves coordination safety?","Versioned state and reversible actions","Assuming every message arrives once","Removing human escalation","Recovery is part of the design."], e:["Two components disagree. What should the protocol define?","Source of truth","Conflict resolution","An escalation and rollback path","Ambiguity becomes risk when action is irreversible."], s:[] },
    { n:"09", t:"Retrieval is not interpretation", l:"A structured index can locate candidate material; using it well still requires context, evaluation, and judgment.", b:["Tokenization divides input into units. Embeddings support retrieval. Attention computes weighted mixtures across positions. Generation estimates plausible continuations.","None of these operations guarantees truth or relevance. A source-grounded system must preserve citations, uncertainty, access rules, and a refusal when evidence is missing."], c:["tokenization","retrieval","attention"], v:"A retrieval pipeline cannot supply truth by itself, complete context, accountable counsel, or evidence that was never indexed.", q:["What should happen when no approved source supports an answer?","Return an explicit unresolved result","Invent a plausible completion","Hide the missing evidence","Abstention is a valid system output."], e:["A retrieved passage looks relevant. What comes next?","Check provenance","Check scope and date","Review whether it answers the actual question","Retrieval begins evaluation; it does not finish it."], s:[] },
    { n:"10", t:"Design the human-facing protocol", l:"Interfaces teach people what a system is, what it knows, and how much authority to grant it.", b:["Labels, defaults, animation, confidence displays, and conversational tone shape behavior. A persuasive surface can produce over-trust even when the underlying model is unchanged.","Good interaction design reveals uncertainty, asks for confirmation before impact, makes refusal legible, and provides a path to inspect evidence and appeal a decision."], c:["human-computer interaction","calibrated trust","consent"], v:"An interface cannot supply informed consent merely by displaying a checkbox, nor can fluency replace evidence.", q:["Which interface encourages calibrated trust?","Visible sources, limits, and correction paths","Human-like certainty without evidence","Irreversible default actions","The surface should reveal the system’s real limits."], e:["Before a high-impact action, what should appear?","A plain-language preview","The evidence and uncertainty","A named confirmation and undo path","Meaningful control occurs before impact."], s:[] },
    { n:"11", t:"Optimize with accountability", l:"An objective function measures a target; it does not define everything worth protecting.", b:["Metrics turn values into quantities, but proxies can be gamed and tradeoffs can disappear. Improving an average can still harm a subgroup or shift cost elsewhere.","Responsible evaluation combines task metrics, subgroup analysis, qualitative review, incident reporting, and named ownership for repair."], c:["objective function","proxy risk","accountability"], v:"Optimization cannot supply a complete moral objective, choose legitimate tradeoffs, or accept responsibility for harm.", q:["What makes an evaluation stronger?","Multiple metrics, subgroup review, and incident ownership","One aggregate score","Ignoring unmeasured effects","Accountability begins where the metric ends."], e:["A metric improves while complaints rise. What should happen?","Investigate the proxy","Read qualitative evidence","Assign repair and revise the objective","The measured target may not equal the real goal."], s:[] },
    { n:"12", t:"Audit the analogy and return", l:"A model for thinking is useful only when its evidence, scope, and stopping point remain visible.", b:["Structural similarity can generate hypotheses. It does not prove shared origin, identical function, or complete explanation.","The final audit names what is observed, what is inferred, what remains unknown, who is affected, and which decision returns to accountable people."], c:["analogy audit","uncertainty","human authority"], v:"A technical explanation cannot supply lived meaning, legitimate authority, moral accountability, or a final answer to every human question.", q:["When is an analogy defensible?","When resemblance, evidence type, and failure point are explicit","When it feels profound","When it replaces source review","A good analogy contains its own stopping rule."], e:["Finish an audit. What must return to people?","High-impact judgment","Responsibility for consequences","The power to contest and repair","Tools may assist; accountable people still own the decision."], s:[] }
  ],
  es: [
    { n:"01", t:"Definir el límite del sistema", l:"Un modelo técnico útil declara qué está dentro, qué queda fuera y quién posee la decisión.", b:["Este recorrido examina entradas, transformaciones, salidas, restricciones y puntos de revisión observables. La fluidez no demuestra comprensión completa.","El límite forma parte de la especificación e impide que una herramienta limitada se convierta silenciosamente en autoridad."], c:["alcance","comportamiento observable","propiedad de la decisión"], v:"Un modelo computacional no aporta experiencia vivida, consentimiento, posición moral independiente ni juicio responsable.", q:["¿Qué contiene una especificación responsable?","Tarea autorizada y exclusiones explícitas","Competencia ilimitada","Propiedad invisible","El alcance permite evaluar."], e:["¿Qué debe nombrar una auditoría?","Personas afectadas","Entradas y salidas permitidas","Responsable humano y vía de apelación","La autoridad explícita aumenta la seguridad."], s:[] },
    { n:"02", t:"Rastrear la procedencia de datos", l:"Los datos llegan mediante historias de recogida, selección, etiquetado, omisión y poder.", b:["Un conjunto de datos no es un espejo neutral. Su cobertura depende de quién fue medido, qué categorías se usaron y qué se descartó.","La procedencia registra fuentes, transformaciones, derechos, fecha y vacíos conocidos. Sin ella, la precisión puede ocultar una base ilegible."], c:["procedencia","sesgo de selección","cobertura"], v:"Más filas no aportan las experiencias excluidas ni reparan por sí solas el daño.", q:["¿Qué mejora la procedencia?","Registrar contexto y vacíos","Borrar el origen tras entrenar","Suponer que la escala elimina sesgos","La trazabilidad permite interpretar."], e:["El rendimiento falla para un grupo. ¿Qué revisar?","Cobertura","Etiquetas y condiciones","Quién definió el éxito","El fallo suele comenzar antes del entrenamiento."], s:[] },
    { n:"03", t:"Versionar taxonomías", l:"Las categorías son decisiones de ingeniería, no hechos naturales descubiertos para siempre.", b:["Etiquetas y clases comprimen situaciones complejas. Cambiar una definición cambia el sistema aunque el código sea igual.","Una taxonomía versionada registra definición, responsable, evidencia y migración; evita significados incompatibles bajo un nombre."], c:["taxonomía","versionado","deriva semántica"], v:"Una clasificación no aporta una descripción final y sin contexto de personas o situaciones cambiantes.", q:["¿Por qué versionar?","Las definiciones y consecuencias cambian.","Cada nombre conserva un significado.","El modelo adivina la intención.","Versionar vuelve visible el significado."], e:["Dos equipos usan una etiqueta de modo distinto. ¿Qué ayuda?","Escribir ambas definiciones","Nombrar responsables","Mapear diferencias","Palabras iguales no garantizan semántica igual."], s:[] },
    { n:"04", t:"Representar relaciones en vectores", l:"Los embeddings sitúan elementos en una geometría aprendida donde la distancia refleja patrones estadísticos.", b:["Un vector no guarda una esencia completa. Es una representación dependiente del contexto y del objetivo.","La cercanía apoya búsqueda y agrupación, pero no prueba causa, valor o significado idénticos. La métrica responde solo a su pregunta."], c:["embeddings","métrica de distancia","representación"], v:"Un vector no aporta contexto completo, significado intrínseco, causalidad ni punto de vista vivido.", q:["¿Qué establece la proximidad?","Relación estadística bajo una métrica","Identidad completa","Equivalencia moral","La similitud geométrica está ligada a la tarea."], e:["Un resultado está cerca. ¿Qué falta revisar?","Contexto de fuente","Pertinencia","Sesgo de la métrica","La distancia es evidencia, no veredicto."], s:[] },
    { n:"05", t:"La memoria tiene varias capas", l:"Memoria puede significar parámetros, ventana de contexto, recuperación externa o estado guardado.", b:["Las capas se comportan distinto. Un prompt cambia activaciones durante inferencia; normalmente no reescribe pesos entrenados.","La memoria organizativa incluye documentos, personas, procedimientos, excepciones y responsabilidad. Una instantánea captura solo una parte."], c:["parámetros","ventana de contexto","recuperación"], v:"El estado almacenado no aporta confianza, práctica tácita, responsabilidad ni explicación completa de cada decisión.", q:["¿Qué cambia un prompt normal?","Activaciones actuales y probabilidades","Todos los pesos","El corpus histórico","Inferencia usa pesos; no suele reentrenarlos."], e:["Una guía necesita política vigente. ¿Qué diseño ayuda?","Recuperar fuente versionada","Mostrar la fecha","Mantener responsable humano","El contexto actual exige rastreo."], s:[] },
    { n:"06", t:"La infraestructura forma parte del modelo", l:"Cómputo, chips, energía, redes, refrigeración, interfaces y trabajo condicionan el sistema.", b:["El comportamiento del software está limitado por recursos físicos y decisiones operativas. Latencia, capacidad y coste ambiental son hechos arquitectónicos.","Una interfaz limpia puede ocultar anotación, operación, moderación y soporte. El mapa completo muestra dependencias."], c:["cómputo","coste material","operación humana"], v:"Una arquitectura abstracta no aporta energía, mantenimiento, derechos laborales, reparación ambiental ni cuidado real.", q:["¿Qué cabe en el diagrama?","Cómputo, personas, energía y fallos","Solo el bloque del modelo","Solo salidas correctas","La infraestructura hace posible la capacidad."], e:["Una función parece instantánea. ¿Qué preguntar?","Dónde se computa","Quién mantiene","Qué costes se externalizan","La interfaz no es todo el sistema."], s:[] },
    { n:"07", t:"Las capacidades emergen en combinación", l:"Sistemas grandes muestran habilidades que no fueron programadas como reglas separadas.", b:["Escala, datos, optimización, instrucciones, herramientas y evaluación interactúan. Algunos cambios graduales se vuelven visibles tras un umbral.","El comportamiento inesperado exige medición, experimentos controlados y despliegue conservador; no demuestra agencia ilimitada."], c:["comportamiento emergente","escala","evaluación"], v:"Una capacidad inesperada no aporta autoconocimiento, propósito, agencia moral ni autorización para actuar.", q:["¿Qué sigue a una capacidad inesperada?","Evaluación específica y nuevas salvaguardas","Afirmar inteligencia ilimitada","Desplegar sin supervisión","La sorpresa exige más evidencia."], e:["El modelo supera una prueba. ¿Qué revisar?","Fuga de prueba","Robustez","Impacto y revisión","Un benchmark no es un mapa completo."], s:[] },
    { n:"08", t:"Coordinar partes interactivas", l:"Los sistemas distribuidos dependen de mensajes, estado, tiempo, autoridad y recuperación.", b:["Un sistema puede ser correcto localmente y peligroso globalmente. Fallos aparecen por estado obsoleto, mensajes perdidos, acciones duplicadas y propiedad difusa.","Los protocolos definen quién actúa, cuál estado vale, cómo resolver conflicto y cómo revertir."], c:["estado distribuido","protocolo","recuperación"], v:"Un protocolo no aporta confianza, propósito compartido, consentimiento ni juicio para toda excepción.", q:["¿Qué mejora la seguridad?","Estado versionado y acciones reversibles","Suponer entrega exacta","Quitar escalamiento humano","Recuperar forma parte del diseño."], e:["Dos componentes discrepan. ¿Qué definir?","Fuente de verdad","Resolución de conflicto","Escalamiento y reversión","La ambigüedad es riesgo si la acción no se revierte."], s:[] },
    { n:"09", t:"Recuperar no es interpretar", l:"Un índice localiza material candidato; usarlo exige contexto, evaluación y juicio.", b:["Tokenización divide entradas; embeddings apoyan búsqueda; atención mezcla posiciones con pesos; generación estima continuaciones.","Ninguna operación garantiza verdad. Un sistema con fuentes conserva citas, incertidumbre, reglas de acceso y rechazo cuando falta evidencia."], c:["tokenización","recuperación","atención"], v:"La tubería no aporta verdad por sí sola, contexto completo, consejo responsable ni evidencia que nunca fue indexada.", q:["¿Qué hacer sin fuente aprobada?","Devolver resultado no resuelto","Inventar una respuesta","Ocultar la falta","Abstenerse es salida válida."], e:["Un pasaje parece pertinente. ¿Qué sigue?","Comprobar procedencia","Comprobar alcance y fecha","Ver si responde la pregunta","Recuperar inicia; no termina la evaluación."], s:[] },
    { n:"10", t:"Diseñar el protocolo humano", l:"Las interfaces enseñan qué es un sistema, qué sabe y cuánta autoridad concederle.", b:["Etiquetas, valores predeterminados, animación, confianza y tono cambian conducta. Una superficie persuasiva puede producir exceso de confianza.","El buen diseño muestra incertidumbre, pide confirmación antes del impacto, hace legible el rechazo y permite inspección y apelación."], c:["interacción","confianza calibrada","consentimiento"], v:"Una interfaz no aporta consentimiento informado con una casilla ni sustituye evidencia con fluidez.", q:["¿Qué interfaz calibra confianza?","Fuentes, límites y corrección visibles","Certeza sin evidencia","Acciones irreversibles por defecto","La superficie debe revelar límites reales."], e:["Antes de una acción de impacto, ¿qué mostrar?","Vista previa clara","Evidencia e incertidumbre","Confirmación y deshacer","El control significativo ocurre antes del impacto."], s:[] },
    { n:"11", t:"Optimizar con responsabilidad", l:"Una función objetivo mide una meta; no define todo lo que merece protección.", b:["Las métricas cuantifican valores, pero los proxies se pueden explotar y ocultar compensaciones. Mejorar un promedio puede dañar a un grupo.","La evaluación combina métricas, subgrupos, revisión cualitativa, incidentes y propiedad de la reparación."], c:["función objetivo","riesgo de proxy","responsabilidad"], v:"Optimizar no aporta un objetivo moral completo, compensaciones legítimas ni responsabilidad por daños.", q:["¿Qué fortalece la evaluación?","Varias métricas, subgrupos e incidentes","Una puntuación agregada","Ignorar efectos no medidos","La responsabilidad empieza donde termina la métrica."], e:["Mejora la métrica y suben las quejas. ¿Qué hacer?","Investigar el proxy","Leer evidencia cualitativa","Revisar el objetivo y reparar","Lo medido puede no ser la meta real."], s:[] },
    { n:"12", t:"Auditar la analogía y devolver", l:"Un modelo para pensar sirve cuando evidencia, alcance y punto de parada permanecen visibles.", b:["La similitud estructural genera hipótesis; no prueba origen compartido, función idéntica ni explicación completa.","La auditoría final distingue observación, inferencia y desconocido, identifica afectados y devuelve la decisión a personas responsables."], c:["auditoría de analogía","incertidumbre","autoridad humana"], v:"Una explicación técnica no aporta significado vivido, autoridad legítima, responsabilidad moral ni respuesta final para toda pregunta.", q:["¿Cuándo es defendible una analogía?","Con semejanza, tipo de evidencia y fallo explícitos","Cuando suena profunda","Cuando sustituye fuentes","Una buena analogía contiene su límite."], e:["¿Qué debe volver a personas?","Juicio de alto impacto","Responsabilidad por consecuencias","Poder de impugnar y reparar","Las herramientas ayudan; las personas responden."], s:[] }
  ],
  "pt-BR": [
    { n:"01", t:"Definir o limite do sistema", l:"Um modelo técnico útil declara o que entra no escopo, o que fica fora e quem responde pela decisão.", b:["Este percurso examina entradas, transformações, saídas, restrições e pontos de revisão observáveis. Fluência não prova compreensão completa.","O limite integra a especificação e impede que uma ferramenta limitada vire autoridade silenciosamente."], c:["escopo","comportamento observável","responsável pela decisão"], v:"Um modelo computacional não oferece experiência vivida, consentimento, posição moral independente ou julgamento responsável.", q:["O que entra numa especificação responsável?","Tarefa autorizada e exclusões explícitas","Competência ilimitada","Responsável invisível","Escopo permite avaliar."], e:["O que uma auditoria deve nomear?","Pessoas afetadas","Entradas e saídas permitidas","Responsável humano e recurso","Autoridade explícita aumenta a segurança."], s:[] },
    { n:"02", t:"Rastrear a proveniência dos dados", l:"Dados chegam por histórias de coleta, seleção, rotulagem, omissão e poder.", b:["Um conjunto de dados não é espelho neutro. Sua cobertura depende de quem foi medido, das categorias e do que foi descartado.","Proveniência registra fontes, transformações, direitos, data e lacunas. Sem isso, precisão pode esconder uma base ilegível."], c:["proveniência","viés de seleção","cobertura"], v:"Mais linhas não oferecem experiências excluídas nem reparam danos automaticamente.", q:["O que melhora a proveniência?","Registrar contexto e lacunas","Apagar a origem após treinar","Supor que escala elimina viés","Rastreabilidade apoia interpretação."], e:["O desempenho falha para um grupo. O que revisar?","Cobertura","Rótulos e condições","Quem definiu sucesso","A falha costuma começar antes do treino."], s:[] },
    { n:"03", t:"Manter taxonomias versionadas", l:"Categorias são decisões de engenharia, não fatos naturais descobertos para sempre.", b:["Rótulos e classes comprimem situações complexas. Mudar uma definição muda o sistema mesmo com o mesmo código.","Uma taxonomia versionada registra definição, responsável, evidência e migração, evitando sentidos incompatíveis sob um nome."], c:["taxonomia","versionamento","deriva semântica"], v:"Classificação não oferece descrição final e sem contexto de pessoas ou situações mutáveis.", q:["Por que versionar?","Definições e consequências mudam.","Nomes sempre mantêm um sentido.","O modelo adivinha a intenção.","Versionar torna significado inspecionável."], e:["Duas equipes usam um rótulo diferente. O que ajuda?","Escrever definições","Nomear responsáveis","Mapear diferenças","Palavras iguais não garantem semântica igual."], s:[] },
    { n:"04", t:"Representar relações em vetores", l:"Embeddings colocam itens numa geometria aprendida em que distância reflete padrões estatísticos.", b:["Um vetor não guarda essência completa. É representação dependente do contexto, corpus, objetivo e arquitetura.","Proximidade apoia busca e agrupamento, mas não prova causa, valor ou sentido idênticos. A métrica responde somente à pergunta construída."], c:["embeddings","métrica de distância","representação"], v:"Um vetor não oferece contexto completo, significado intrínseco, causalidade ou ponto de vista vivido.", q:["O que a proximidade estabelece?","Relação estatística sob uma métrica","Identidade completa","Equivalência moral","Semelhança geométrica depende da tarefa."], e:["Um resultado está próximo. O que revisar?","Contexto da fonte","Relevância","Viés da métrica","Distância é evidência, não veredito."], s:[] },
    { n:"05", t:"Memória vive em várias camadas", l:"Memória pode significar parâmetros, janela de contexto, recuperação externa ou estado salvo.", b:["As camadas se comportam de modo diferente. Um prompt muda ativações durante inferência; normalmente não reescreve pesos treinados.","Memória organizacional inclui documentos, pessoas, procedimentos, exceções e responsabilidade. Um snapshot captura só uma parte."], c:["parâmetros","janela de contexto","recuperação"], v:"Estado armazenado não oferece confiança, prática tácita, responsabilidade ou explicação completa das decisões.", q:["O que um prompt comum muda?","Ativações atuais e probabilidades","Todos os pesos","O corpus histórico","Inferência usa pesos; normalmente não retreina."], e:["Um guia precisa de política atual. Que desenho ajuda?","Recuperar fonte versionada","Mostrar a data","Manter responsável humano","Contexto atual exige rastreabilidade."], s:[] },
    { n:"06", t:"Infraestrutura faz parte do modelo", l:"Computação, chips, energia, redes, resfriamento, interfaces e trabalho moldam o sistema.", b:["O comportamento é limitado por recursos físicos e decisões operacionais. Latência, capacidade e custo ambiental são fatos de arquitetura.","Uma interface limpa pode esconder anotação, operação, moderação e suporte. O mapa completo mostra dependências."], c:["computação","custo material","operação humana"], v:"Arquitetura abstrata não oferece energia, manutenção, direitos trabalhistas, reparação ambiental ou cuidado real.", q:["O que entra no diagrama?","Computação, pessoas, energia e falhas","Só o bloco do modelo","Só saídas corretas","Infraestrutura torna capacidade possível."], e:["Uma função parece instantânea. O que perguntar?","Onde computa","Quem mantém","Que custos são externalizados","A interface não é o sistema inteiro."], s:[] },
    { n:"07", t:"Capacidades emergem em combinação", l:"Sistemas grandes exibem habilidades que não foram programadas como regras isoladas.", b:["Escala, dados, otimização, instruções, ferramentas e avaliação interagem. Mudanças graduais podem ficar visíveis após um limiar.","Comportamento inesperado exige medição, experimentos controlados e implantação conservadora, não afirmação de agência ilimitada."], c:["comportamento emergente","escala","avaliação"], v:"Capacidade inesperada não oferece autoconhecimento, propósito, agência moral ou autorização para agir.", q:["O que segue uma capacidade inesperada?","Avaliação específica e novas proteções","Inteligência ilimitada","Implantação sem supervisão","Surpresa exige mais evidência."], e:["O modelo passa num teste novo. O que revisar?","Vazamento de teste","Robustez","Impacto e revisão","Um benchmark não é mapa completo."], s:[] },
    { n:"08", t:"Coordenar partes interativas", l:"Sistemas distribuídos dependem de mensagens, estado, tempo, autoridade e recuperação.", b:["Um sistema pode ser correto localmente e inseguro no todo. Falhas surgem por estado antigo, mensagens perdidas, ações duplicadas e responsabilidade difusa.","Protocolos definem quem age, qual estado vale, como resolver conflito e como reverter."], c:["estado distribuído","protocolo","recuperação"], v:"Um protocolo não oferece confiança, propósito compartilhado, consentimento ou julgamento para cada exceção.", q:["O que melhora a segurança?","Estado versionado e ações reversíveis","Supor entrega perfeita","Remover escalonamento humano","Recuperação faz parte do projeto."], e:["Dois componentes discordam. O que definir?","Fonte da verdade","Resolução de conflito","Escalonamento e rollback","Ambiguidade vira risco quando a ação não reverte."], s:[] },
    { n:"09", t:"Recuperar não é interpretar", l:"Um índice localiza material candidato; usar bem exige contexto, avaliação e julgamento.", b:["Tokenização divide entradas; embeddings apoiam busca; atenção mistura posições com pesos; geração estima continuações.","Nenhuma operação garante verdade. Um sistema fundamentado preserva fontes, incerteza, acesso e recusa quando falta evidência."], c:["tokenização","recuperação","atenção"], v:"A cadeia não oferece verdade sozinha, contexto completo, conselho responsável ou evidência nunca indexada.", q:["O que fazer sem fonte aprovada?","Retornar resultado não resolvido","Inventar conclusão plausível","Esconder a falta","Abstenção é saída válida."], e:["Uma passagem parece relevante. O que vem depois?","Checar proveniência","Checar escopo e data","Ver se responde à pergunta","Recuperar inicia; não termina a avaliação."], s:[] },
    { n:"10", t:"Projetar o protocolo humano", l:"Interfaces ensinam o que um sistema é, o que sabe e quanta autoridade receberá.", b:["Rótulos, padrões, animação, confiança e tom mudam comportamento. Uma superfície persuasiva pode gerar confiança excessiva.","Bom design revela incerteza, pede confirmação antes do impacto, torna recusa legível e oferece inspeção e recurso."], c:["interação","confiança calibrada","consentimento"], v:"Uma interface não oferece consentimento informado com uma caixa nem substitui evidência por fluência.", q:["Que interface calibra confiança?","Fontes, limites e correção visíveis","Certeza sem evidência","Ação irreversível padrão","A superfície deve revelar limites reais."], e:["Antes de ação de impacto, o que mostrar?","Prévia clara","Evidência e incerteza","Confirmação e desfazer","Controle significativo ocorre antes do impacto."], s:[] },
    { n:"11", t:"Otimizar com responsabilidade", l:"Uma função objetivo mede um alvo; não define tudo o que merece proteção.", b:["Métricas quantificam valores, mas proxies podem ser explorados e esconder trocas. Melhorar média pode prejudicar um grupo.","Avaliação responsável combina métricas, subgrupos, revisão qualitativa, incidentes e dono da reparação."], c:["função objetivo","risco de proxy","responsabilidade"], v:"Otimização não oferece objetivo moral completo, trocas legítimas ou responsabilidade por dano.", q:["O que fortalece a avaliação?","Múltiplas métricas, subgrupos e incidentes","Um único placar","Ignorar efeitos não medidos","Responsabilidade começa onde a métrica termina."], e:["Métrica melhora e queixas crescem. O que fazer?","Investigar o proxy","Ler evidência qualitativa","Rever objetivo e reparar","O medido pode não ser a meta real."], s:[] },
    { n:"12", t:"Auditar a analogia e devolver", l:"Um modelo de pensamento é útil quando evidência, escopo e ponto de parada permanecem visíveis.", b:["Semelhança estrutural gera hipóteses; não prova origem comum, função idêntica ou explicação completa.","A auditoria final separa observado, inferido e desconhecido, identifica afetados e devolve decisão a pessoas responsáveis."], c:["auditoria de analogia","incerteza","autoridade humana"], v:"Explicação técnica não oferece significado vivido, autoridade legítima, responsabilidade moral ou resposta final a toda questão.", q:["Quando uma analogia é defensável?","Com semelhança, evidência e falha explícitas","Quando parece profunda","Quando substitui fontes","Boa analogia contém seu limite."], e:["O que deve voltar às pessoas?","Julgamento de alto impacto","Responsabilidade por consequências","Poder de contestar e reparar","Ferramentas ajudam; pessoas respondem."], s:[] }
  ],
  it: [
    { n:"01", t:"Definire il confine del sistema", l:"Un modello tecnico utile dichiara ciò che è incluso, ciò che resta fuori e chi possiede la decisione.", b:["Il percorso esamina input, trasformazioni, output, vincoli e punti di revisione osservabili. La fluidità non prova comprensione completa.","Il confine fa parte della specifica e impedisce che uno strumento limitato diventi silenziosamente autorità."], c:["ambito","comportamento osservabile","proprietà della decisione"], v:"Un modello computazionale non fornisce esperienza vissuta, consenso, posizione morale indipendente o giudizio responsabile.", q:["Che cosa contiene una specifica responsabile?","Compito autorizzato ed esclusioni esplicite","Competenza illimitata","Responsabile invisibile","L'ambito rende possibile valutare."], e:["Che cosa deve nominare un audit?","Persone coinvolte","Input e output consentiti","Responsabile umano e ricorso","L'autorità esplicita aumenta la sicurezza."], s:[] },
    { n:"02", t:"Tracciare la provenienza dei dati", l:"I dati arrivano attraverso storie di raccolta, selezione, etichettatura, omissione e potere.", b:["Un insieme di dati non è uno specchio neutro. La copertura dipende da chi è stato misurato, dalle categorie e da ciò che è stato scartato.","La provenienza registra fonti, trasformazioni, diritti, data e lacune. Senza, la precisione può nascondere una base illeggibile."], c:["provenienza","bias di selezione","copertura"], v:"Più righe non forniscono esperienze escluse né riparano automaticamente il danno.", q:["Che cosa migliora la provenienza?","Registrare contesto e lacune","Cancellare l'origine dopo l'addestramento","Supporre che la scala elimini il bias","La tracciabilità sostiene l'interpretazione."], e:["La resa peggiora per un gruppo. Che cosa verificare?","Copertura","Etichette e condizioni","Chi ha definito il successo","Il fallimento spesso nasce prima dell'addestramento."], s:[] },
    { n:"03", t:"Versionare le tassonomie", l:"Le categorie sono decisioni ingegneristiche, non fatti naturali scoperti una volta per tutte.", b:["Etichette e classi comprimono situazioni complesse. Cambiare una definizione cambia il sistema anche con lo stesso codice.","Una tassonomia versionata registra definizione, responsabile, prove e migrazione, evitando significati incompatibili sotto un nome."], c:["tassonomia","versionamento","deriva semantica"], v:"Una classificazione non fornisce una descrizione finale e priva di contesto di persone o situazioni mutevoli.", q:["Perché versionare?","Definizioni e conseguenze cambiano.","Ogni nome mantiene un significato.","Il modello indovina l'intenzione.","Versionare rende il significato ispezionabile."], e:["Due gruppi usano una stessa etichetta diversamente. Che cosa aiuta?","Scrivere le definizioni","Nominare i responsabili","Mappare le differenze","Parole uguali non garantiscono semantica uguale."], s:[] },
    { n:"04", t:"Rappresentare relazioni in vettori", l:"Gli embedding collocano elementi in una geometria appresa dove la distanza riflette schemi statistici.", b:["Un vettore non conserva un'essenza completa. È una rappresentazione dipendente da contesto, corpus, obiettivo e architettura.","La vicinanza aiuta ricerca e raggruppamento, ma non prova causa, valore o significato identici. La metrica risponde solo alla domanda progettata."], c:["embedding","metrica di distanza","rappresentazione"], v:"Un vettore non fornisce contesto completo, significato intrinseco, causalità o punto di vista vissuto.", q:["Che cosa stabilisce la prossimità?","Relazione statistica sotto una metrica","Identità completa","Equivalenza morale","La somiglianza geometrica è legata al compito."], e:["Un risultato è vicino. Che cosa va verificato?","Contesto della fonte","Pertinenza","Bias della metrica","La distanza è prova, non verdetto."], s:[] },
    { n:"05", t:"La memoria vive in più strati", l:"Memoria può indicare parametri, finestra di contesto, recupero esterno o stato salvato.", b:["Gli strati si comportano diversamente. Un prompt cambia le attivazioni durante l'inferenza; di norma non riscrive i pesi addestrati.","La memoria organizzativa include documenti, persone, procedure, eccezioni e responsabilità. Un'istantanea ne cattura solo una parte."], c:["parametri","finestra di contesto","recupero"], v:"Lo stato memorizzato non fornisce fiducia, pratica tacita, responsabilità o spiegazione completa delle decisioni.", q:["Che cosa cambia un prompt ordinario?","Attivazioni attuali e probabilità","Tutti i pesi","Il corpus storico","L'inferenza usa i pesi; di norma non li riaddestra."], e:["Una guida richiede regole aggiornate. Che cosa aiuta?","Recuperare una fonte versionata","Mostrare la data","Mantenere un responsabile umano","Il contesto attuale richiede tracciabilità."], s:[] },
    { n:"06", t:"L'infrastruttura fa parte del modello", l:"Calcolo, chip, energia, reti, raffreddamento, interfacce e lavoro modellano il sistema.", b:["Il comportamento è limitato da risorse fisiche e scelte operative. Latenza, capacità e costo ambientale sono fatti architetturali.","Un'interfaccia pulita può nascondere annotazione, operazioni, moderazione e supporto. La mappa completa mostra le dipendenze."], c:["calcolo","costo materiale","operazioni umane"], v:"Un'architettura astratta non fornisce energia, manutenzione, diritti del lavoro, riparazione ambientale o cura reale.", q:["Che cosa entra nel diagramma?","Calcolo, persone, energia e gestione errori","Solo il blocco del modello","Solo output corretti","L'infrastruttura rende possibile la capacità."], e:["Una funzione sembra istantanea. Che cosa chiedere?","Dove avviene il calcolo","Chi mantiene","Quali costi sono esternalizzati","L'interfaccia non è l'intero sistema."], s:[] },
    { n:"07", t:"Le capacità emergono in combinazione", l:"Sistemi grandi mostrano abilità non programmate come regole separate.", b:["Scala, dati, ottimizzazione, istruzioni, strumenti e valutazione interagiscono. Cambiamenti graduali possono apparire dopo una soglia.","Il comportamento inatteso richiede misure, esperimenti controllati e distribuzione prudente, non affermazioni di autonomia illimitata."], c:["comportamento emergente","scala","valutazione"], v:"Una capacità inattesa non fornisce autocoscienza, scopo, azione morale o autorizzazione ad agire.", q:["Che cosa segue una capacità inattesa?","Valutazione mirata e nuove protezioni","Intelligenza illimitata","Distribuzione senza supervisione","La sorpresa richiede più prove."], e:["Il modello supera un nuovo test. Che cosa controllare?","Contaminazione del test","Robustezza","Impatto e revisione","Un benchmark non è una mappa completa."], s:[] },
    { n:"08", t:"Coordinare parti interattive", l:"I sistemi distribuiti dipendono da messaggi, stato, tempo, autorità e recupero.", b:["Un sistema può essere corretto localmente e insicuro nel complesso. Errori nascono da stato vecchio, messaggi persi, azioni duplicate e proprietà confusa.","I protocolli definiscono chi agisce, quale stato vale, come risolvere conflitti e come tornare indietro."], c:["stato distribuito","protocollo","recupero"], v:"Un protocollo non fornisce fiducia, scopo condiviso, consenso o giudizio per ogni eccezione.", q:["Che cosa migliora la sicurezza?","Stato versionato e azioni reversibili","Supporre consegna perfetta","Rimuovere l'escalation umana","Il recupero è parte del progetto."], e:["Due componenti divergono. Che cosa definire?","Fonte di verità","Risoluzione conflitti","Escalation e rollback","L'ambiguità è rischio quando l'azione non si annulla."], s:[] },
    { n:"09", t:"Recuperare non è interpretare", l:"Un indice localizza materiale candidato; usarlo bene richiede contesto, valutazione e giudizio.", b:["La tokenizzazione divide gli input; gli embedding aiutano la ricerca; l'attenzione combina posizioni con pesi; la generazione stima continuazioni.","Nessuna operazione garantisce verità. Un sistema fondato conserva fonti, incertezza, accesso e rifiuto quando mancano prove."], c:["tokenizzazione","recupero","attenzione"], v:"La catena non fornisce verità da sola, contesto completo, consiglio responsabile o prove mai indicizzate.", q:["Che fare senza fonte approvata?","Restituire risultato irrisolto","Inventare una conclusione","Nascondere la mancanza","Astenersi è un output valido."], e:["Un passaggio sembra pertinente. Che cosa segue?","Verificare provenienza","Verificare ambito e data","Controllare se risponde","Il recupero avvia, non chiude la valutazione."], s:[] },
    { n:"10", t:"Progettare il protocollo umano", l:"Le interfacce insegnano che cosa è un sistema, che cosa sa e quanta autorità ricevere.", b:["Etichette, valori predefiniti, animazione, confidenza e tono cambiano il comportamento. Una superficie persuasiva può produrre fiducia eccessiva.","Un buon progetto rivela incertezza, chiede conferma prima dell'impatto, rende leggibile il rifiuto e offre ispezione e ricorso."], c:["interazione","fiducia calibrata","consenso"], v:"Un'interfaccia non fornisce consenso informato con una casella né sostituisce prove con fluidità.", q:["Quale interfaccia calibra la fiducia?","Fonti, limiti e correzioni visibili","Certezza senza prove","Azioni irreversibili predefinite","La superficie deve rivelare limiti reali."], e:["Prima di un'azione importante, che cosa mostrare?","Anteprima chiara","Prove e incertezza","Conferma e annullamento","Il controllo significativo viene prima dell'impatto."], s:[] },
    { n:"11", t:"Ottimizzare con responsabilità", l:"Una funzione obiettivo misura un bersaglio; non definisce tutto ciò che va protetto.", b:["Le metriche quantificano valori, ma i proxy possono essere manipolati e nascondere compromessi. Migliorare una media può danneggiare un gruppo.","La valutazione responsabile combina metriche, sottogruppi, revisione qualitativa, incidenti e proprietà della riparazione."], c:["funzione obiettivo","rischio proxy","responsabilità"], v:"L'ottimizzazione non fornisce un obiettivo morale completo, compromessi legittimi o responsabilità per il danno.", q:["Che cosa rafforza la valutazione?","Metriche multiple, sottogruppi e incidenti","Un solo punteggio","Ignorare effetti non misurati","La responsabilità inizia dove finisce la metrica."], e:["La metrica migliora e le lamentele crescono. Che fare?","Indagare il proxy","Leggere prove qualitative","Rivedere obiettivo e riparare","Ciò che si misura può non essere la meta reale."], s:[] },
    { n:"12", t:"Verificare l'analogia e restituire", l:"Un modello di pensiero serve quando prove, ambito e punto di arresto restano visibili.", b:["La somiglianza strutturale genera ipotesi; non prova origine comune, funzione identica o spiegazione completa.","L'audit finale distingue osservato, inferito e ignoto, identifica le persone coinvolte e restituisce la decisione a responsabili umani."], c:["audit dell'analogia","incertezza","autorità umana"], v:"Una spiegazione tecnica non fornisce significato vissuto, autorità legittima, responsabilità morale o risposta finale a ogni domanda.", q:["Quando è difendibile un'analogia?","Con somiglianza, prova e fallimento espliciti","Quando sembra profonda","Quando sostituisce le fonti","Una buona analogia contiene il proprio limite."], e:["Che cosa deve tornare alle persone?","Giudizio ad alto impatto","Responsabilità delle conseguenze","Potere di contestare e riparare","Gli strumenti aiutano; le persone rispondono."], s:[] }
  ]
};

