const aiGlossary = aiLessons.en.map((_, index) => ({
  term: aiLessons.en[index].c[0],
  content: Object.fromEntries(locales.map((locale) => [locale, {
    term: aiLessons[locale][index].c[0],
    definition: aiLessons[locale][index].l,
    limit: aiLessons[locale][index].v
  }]))
}));

function comparison(concept, records) {
  return {
    concept,
    content: Object.fromEntries(locales.map((locale) => [locale, {
      concept,
      ...records[locale]
    }]))
  };
}

